import { NextRequest, NextResponse } from "next/server";
import bcrypt from "bcryptjs";
import { connectDB } from "@/lib/db"; // O la ruta correcta a tu db.ts
import User from "@/models/user";

export async function POST(request: NextRequest) {
  try {
    const { email, password } = await request.json();
    if (!email || !password) {
      return NextResponse.json({ error: "Faltan datos" }, { status: 400 });
    }
    
    // Conecta a la base de datos
    await connectDB();
    
    // Lógica para verificar si el usuario existe, hashear la contraseña y guardar el usuario
    // ...
    
    return NextResponse.json({ message: "Usuario registrado correctamente" }, { status: 201 });
  } catch (error: any) {
    console.error(error);
    return NextResponse.json({ error: "Error al registrar el usuario" }, { status: 500 });
  }
}
